INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Automatic Time Tracking$q$, $q$Logs time spent in apps, documents, and websites in the background with no manual timers to start or stop.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Productivity Scoring$q$, $q$Classifies each app and site as productive, distracting, or neutral using customizable category rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Focus Sessions$q$, $q$Temporarily blocks distracting sites and apps to protect a dedicated block of deep-work time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Detailed Activity Reports$q$, $q$Daily and weekly dashboards break down time by category, application, website, and time of day.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Goals and Alerts$q$, $q$Set targets like limiting time on email or social media and receive real-time email or push notifications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Offline Time Tracking$q$, $q$Manually log time spent away from the computer so reports reflect a fuller picture of the day.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Automated Timesheets$q$, $q$Converts tracked activity into timesheet-style entries on Solo+ and Team+ plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Cross-Platform Apps$q$, $q$Native apps for Mac and Windows plus mobile apps keep tracking consistent across devices.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team Dashboards$q$, $q$Aggregate, privacy-conscious reporting gives managers visibility into team productivity trends.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Browser Extensions$q$, $q$Extensions categorize time at the URL level rather than just logging overall browser usage.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Fully automatic tracking removes the need to manually start or stop timers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Generous free Lite tier lets users try the core experience at no cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Granular, customizable categorization of apps and websites by productivity level$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Focus Sessions and alerts provide real, actionable nudges to reduce distraction$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Cross-platform coverage across Mac, Windows, and mobile keeps data consistent$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Free Lite plan is capped at two weeks of history and lacks Focus Sessions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Not designed for detailed client invoicing or task-level project billing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Requires trust in software running continuously in the background on a device$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team plans carry a per-user minimum that raises the cost for small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Category-based reports offer less granular detail than task-level time trackers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Is RescueTime free to use?$q$, $q$Yes, the Lite plan is free and includes automatic tracking and basic activity reports, though history is limited and features like Focus Sessions require a paid Solo or Team plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Does RescueTime take screenshots or log keystrokes?$q$, $q$No, RescueTime tracks time spent by app, document, and website category rather than capturing screenshots or recording keystrokes.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$What platforms does RescueTime support?$q$, $q$RescueTime offers native apps for Mac and Windows, mobile apps for iOS and Android, and browser extensions for more precise website tracking.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Can RescueTime block distracting websites?$q$, $q$Yes, Focus Sessions on paid plans temporarily block chosen distracting sites and apps for a set period to support deep work.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Does RescueTime offer team pricing?$q$, $q$Yes, Team Focus and Team+ plans are billed per user and add aggregate team productivity dashboards alongside individual reporting.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Freelance time and effort audit$q$, $q$Freelancers use RescueTime's automatic logs to see how project hours are actually spent without maintaining a manual timesheet.$q$, $q$Freelancers and independent contractors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Remote team productivity visibility$q$, $q$Managers review aggregate, category-level reports to understand team workload and communication patterns without invasive monitoring.$q$, $q$Managers of distributed teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Digital wellbeing and distraction reduction$q$, $q$Individuals set goals and alerts to cut down on social media or news browsing and build healthier daily computer habits.$q$, $q$Individuals focused on digital wellbeing$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Protecting deep-work blocks$q$, $q$Developers and writers use Focus Sessions to block distracting apps and sites during scheduled deep-work periods.$q$, $q$Developers, writers, and designers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Lite$q$, $q$Free$q$, $q$N/A$q$, $q$["Automatic activity tracking","Basic activity reports","Up to two weeks of history","One goal","Weekly summary email"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Solo Focus$q$, $q$$7/month billed annually ($9/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Unlimited history","Focus Sessions","Goals and alerts","Detailed personal productivity reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Solo+$q$, $q$$12/month billed annually ($15/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Solo Focus","Automated timesheets","Project time tracking"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team Focus$q$, $q$$10/user/month billed annually ($12/user/month billed monthly)$q$, $q$Monthly or annual, per user$q$, $q$["Individual and team productivity reports","Daily pattern analysis","Key tools tracking"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RescueTime is an automatic time-tracking and productivity analytics tool that runs quietly in the background on desktop and mobile devices, recording how time is spent across applications, websites, and documents without requiring manual timers. Founded in 2007 and headquartered in Seattle, Washington, the company built its reputation among freelancers, remote teams, and productivity-minded professionals who want to understand where their attention actually goes during the workday.$q$, $q$Unlike stopwatch-style trackers that depend on someone remembering to start and stop a clock, RescueTime installs as a lightweight background process that logs activity automatically, then assigns a productivity score to each app or site based on customizable categories. The result is a daily and weekly dashboard showing how many hours went to deep work, meetings, communication tools, or distractions like social media and news sites.$q$, $q$The free Lite tier offers basic activity tracking and a two-week history, while the paid Solo and Team plans unlock Focus Sessions, distraction blocking, alerts, offline time logging, and unlimited historical reporting. This freemium structure lets individuals try the core tracking experience before subscribing, positioning RescueTime as an accessible entry point into the broader time-tracking and digital-wellbeing software category alongside tools such as Toggl and Timely.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$who-rescuetime-is-for$q$, $q$Who RescueTime Is For$q$, 2, ARRAY[$q$RescueTime suits knowledge workers, freelancers, and remote employees who want an honest, automatic picture of how they spend computer time rather than a manually logged timesheet. Developers, writers, designers, and consultants who bill by the hour, or who simply want to protect deep-focus blocks from constant app-switching, tend to get the most value from its passive tracking model.$q$, $q$Managers of small distributed teams can use the Team plans to spot burnout risk or communication overload by reviewing aggregate, category-level productivity trends rather than screenshots or keystroke logs, making RescueTime a gentler alternative to invasive employee-monitoring software for teams that value autonomy and trust over surveillance.$q$, $q$Students and self-improvement-minded individuals who want to curb social media or news habits are another core audience, since the goals, alerts, and Focus Session blocking features act as a lightweight accountability layer that nudges behavior change without requiring willpower alone.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need detailed, screenshot-based or keystroke-level employee surveillance should look elsewhere, since RescueTime intentionally avoids screen capture and granular input monitoring in favor of category-level activity summaries; it was never designed as a compliance or surveillance tool.$q$, $q$Teams that need built-in client invoicing, project budgeting, or task-level billable-hour timesheets may find RescueTime's timesheet features thinner than dedicated tools such as Harvest or Toggl Track, which are purpose-built around client billing and project accounting workflows.$q$, $q$Users who work primarily on shared, locked-down, or IT-managed devices where background software cannot be installed, or who need tracking across tablets and other devices beyond desktop and mobile apps, may run into coverage gaps that limit how useful RescueTime can be for them.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, RescueTime offers automatic activity tracking with no manual start or stop, paired with a productivity scoring system that classifies each application, document, and website as productive, distracting, or neutral, then rolls the data into daily and weekly reports broken down by category, app, and time of day.$q$, $q$Focus Sessions temporarily block distracting sites and apps so users can protect a stretch of deep work, while goals and alerts flag when time spent on a category crosses a self-set threshold, sending an email or push notification as a real-time nudge rather than only a retrospective report.$q$, $q$Paid plans add offline time logging for tracking time away from the computer, automated timesheets that turn tracked activity into billable-style entries, and team dashboards that give managers aggregate visibility into group productivity trends without exposing individual screenshots or keystrokes.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$the-rescuetime-experience$q$, $q$The RescueTime Experience$q$, 2, ARRAY[$q$Getting started with RescueTime is largely hands-off: after installing the desktop app or mobile app and granting activity-tracking permissions, the software begins categorizing time automatically, and most users see their first meaningful dashboard within a day of normal computer use.$q$, $q$The daily and weekly email summaries are where the experience tends to land emotionally, showing productivity pulse scores, top distractions, and how a given day compared with personal averages, which many users describe as a quietly motivating nudge rather than a nagging one.$q$, $q$Overall, the experience favors reflection over enforcement unless Focus Sessions and alerts are actively configured, so users who invest a little time in setting goals and categories tend to get considerably more value than those who install it and never revisit the settings.$q$]::text[], 4);
