INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Drag-and-Drop Scheduling$q$, $q$A visual grid for booking people, equipment, and rooms against projects with simple drag-and-drop actions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Clash Management$q$, $q$Automatic warnings for double-bookings and overtime so managers can catch scheduling conflicts before they happen.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Availability Bar$q$, $q$An at-a-glance view of who has spare capacity, making it faster to assign new work to the right person.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Leave Management$q$, $q$Staff can request time off and managers approve it directly in the schedule, keeping availability accurate.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Utilization and Forecast Reports$q$, $q$Reporting on how busy people and teams are over time, useful for capacity planning and hiring decisions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Custom Fields and Booking Categories$q$, $q$Configurable fields and categories let teams tailor bookings to their own workflows and terminology.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Waiting List$q$, $q$A holding area for tentative or unconfirmed bookings that haven't yet been placed on the live schedule.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Multiple Resource Types$q$, $q$Schedule people, equipment, and meeting rooms together in the same shared calendar.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$API and Calendar Sync$q$, $q$An open API plus calendar sync and Slack notifications for connecting schedules to other tools.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Simple, visual drag-and-drop interface that is fast to learn compared with full project management suites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Handles people, equipment, and rooms in a single shared schedule$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Utilization and forecast reporting supports practical capacity planning decisions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Quick setup with a 30-day free trial and no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Per-person tiered pricing keeps costs predictable for growing teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$No free plan is available; all use requires a paid subscription after the trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Lacks deep project management features like task dependencies or Gantt charts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Limited native time tracking and invoicing compared with broader work management platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Advanced reporting and custom fields are locked behind higher-priced tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Per-person pricing can add up for larger teams that book many resources$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Does Resource Guru offer a free plan?$q$, $q$No, Resource Guru does not have a permanent free plan. It offers a 30-day free trial that does not require a credit card, after which continued use requires a paid subscription on one of its per-person plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$How is Resource Guru priced?$q$, $q$Resource Guru charges per person per month across three tiers: Grasshopper, Blackbelt, and Master. Prices are lower when billed annually, and additional non-person resources such as equipment or rooms are billed at a separate per-item rate.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Can Resource Guru schedule equipment and rooms, not just people?$q$, $q$Yes. Resource Guru supports multiple resource types, so equipment, meeting rooms, and other shared assets can be booked in the same schedule alongside people.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Does Resource Guru integrate with other tools?$q$, $q$Resource Guru offers calendar sync, Slack notifications, and an open API for building custom integrations, though its built-in integration library is narrower than that of larger all-in-one project management platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Is Resource Guru a good fit for detailed project management?$q$, $q$Not on its own. Resource Guru focuses on scheduling and availability rather than task dependencies, Gantt charts, or detailed budgeting, so many teams pair it with a separate project management tool.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Agency Resource Scheduling$q$, $q$Creative, marketing, and digital agencies use Resource Guru to see which staff are free and assign them to client projects without double-booking.$q$, $q$Creative and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Professional Services Capacity Planning$q$, $q$Consulting, engineering, and architecture firms match billable staff to project demand and track utilization to inform staffing and hiring decisions.$q$, $q$Consultancies and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Combined People and Equipment Booking$q$, $q$Teams that need to schedule cameras, studios, meeting rooms, or other shared equipment alongside staff manage everything in one calendar.$q$, $q$Production, studio, and operations teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Cross-Department Utilization Reporting$q$, $q$Operations and resource managers use forecast and utilization reports to spot overbooked or underused teams before it becomes a problem.$q$, $q$Operations and resource managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Grasshopper$q$, $q$$5 per person/month (billed monthly); $4.16 per person/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Drag-and-drop scheduling","Unlimited projects and clients","Personalized dashboards","Custom filters","Calendar sync"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Blackbelt$q$, $q$$8 per person/month (billed monthly); $5.33 per person/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Everything in Grasshopper","Timesheets","Customizable reports","Project dates and milestones","Project rates and budgets","Custom fields"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Master$q$, $q$$12 per person/month (billed monthly); $8 per person/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Everything in Blackbelt","Approval workflows","Single sign-on (SSO)","Unlimited activity history","Unlimited custom fields","Phone support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Resource Guru is a cloud-based resource scheduling and team availability platform founded in 2011 and headquartered in London, United Kingdom. Rather than trying to be a full project management suite, it focuses narrowly on one job: giving managers a fast, visual way to see who and what is booked, for how long, and where the gaps are, without wading through a heavier all-in-one system built for a much wider set of use cases.$q$, $q$The core of the product is a drag-and-drop scheduling grid that lets you book people, equipment, and meeting rooms against projects or clients in a single shared calendar. Color coding, clash warnings, and an availability bar make it easy to spot overbooking or idle capacity at a glance, without digging through spreadsheets, whiteboards, or several disconnected calendar tools that don't talk to each other.$q$, $q$Layered on top of the scheduler are leave management, utilization and forecast reporting, custom fields, and an API for connecting to other systems already in use. The result is a lightweight, purpose-built alternative to heavier project management platforms for teams whose main planning problem is matching finite people, equipment, and space to competing project demand across a busy week.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$who-resource-guru-is-for$q$, $q$Who Resource Guru Is For$q$, 2, ARRAY[$q$Resource Guru is best suited to agencies, consultancies, and professional services firms that run many concurrent projects and need to keep visibility of who is free, who is overloaded, and when a project can realistically start. Creative agencies, marketing shops, and engineering or architecture practices are common users because their billable staff are shared across multiple client engagements at once, often shifting week to week.$q$, $q$It also fits organizations that need to schedule more than just people, such as production companies booking cameras and studios, or professional services teams booking meeting rooms and shared equipment alongside staff. Being able to manage people and physical resources in the same calendar, rather than juggling separate booking systems for each, is a core part of its appeal for these teams.$q$, $q$Operations managers, resource managers, and team leads who are responsible for capacity planning tend to get the most value from the tool, since utilization reports and forecasting views are built around exactly that kind of day-to-day staffing decision rather than long-term project financials. Growing teams that have outgrown shared spreadsheets but do not need a full project management suite are a natural fit as well.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need deep project management, such as task-level dependencies, Gantt charts, or detailed budget tracking baked into the same tool, will likely find Resource Guru too narrow. It deliberately leaves that functionality out in favor of doing scheduling well, so it is often paired with, rather than used instead of, a broader project management system for planning the work itself.$q$, $q$Organizations that expect built-in invoicing, deep native time tracking beyond basic timesheets, or an extensive marketplace of pre-built integrations may also find the feature set thinner than larger all-in-one platforms. Advanced automation and reporting needs beyond utilization and forecasting are generally addressed through the API or third-party connectors rather than delivered out of the box as native functionality.$q$, $q$Very small teams or solo freelancers who only manage their own time, without equipment, rooms, or other people to coordinate, are unlikely to need a dedicated scheduling tool at all, and a simple calendar may serve them just as well without the added per-person cost of a specialized platform built for shared, multi-resource scheduling problems.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Resource Guru is its drag-and-drop scheduling grid, which supports bookings for people, equipment, and meeting rooms in one shared view. Clash management flags double-bookings and overtime, while the availability bar surfaces who has spare capacity so managers can assign new work without guesswork or back-and-forth messages to confirm someone's schedule.$q$, $q$Leave management lets staff request time off and managers approve it directly against the same schedule, so vacations and absences are automatically reflected in availability without a separate HR process. Custom fields, booking categories, and a waiting list for unconfirmed or tentative work give teams flexibility to model their own workflows on top of the base scheduler.$q$, $q$On the reporting side, utilization and forecast reports show how busy people and teams are over time, helping with hiring, budgeting, and capacity decisions. An open API, calendar sync, and Slack notifications support integration with the rest of a team's existing toolset, and personalized dashboards give each user a filtered view of only the schedule relevant to their own work.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$the-resource-guru-experience$q$, $q$The Resource Guru Experience$q$, 2, ARRAY[$q$New teams can get started quickly: the 30-day free trial requires no credit card, and the scheduling grid is designed to be usable without a lengthy onboarding process or a formal implementation project. Because the product intentionally limits its scope, most new users can start booking resources, inviting teammates, and building out a working schedule within a single session.$q$, $q$Reviewers and long-time users consistently describe the interface as clean and fast compared with heavier project and resource management suites, which is a deliberate design choice rather than an accident of a narrower feature set. The tradeoff is that teams needing deeper project management capabilities often run Resource Guru alongside another tool rather than in place of one, using each for what it does best.$q$, $q$Day-to-day use centers on the shared calendar view, with a self-serve help center and, on the Master plan, phone support available when questions come up. As a responsive web application, it is accessible from desktop and mobile browsers, so managers and staff can check or adjust schedules on the go without needing a dedicated native app installed on their device.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Multiplatform simultaneous broadcasting$q$, $q$Send one live video source to dozens of destinations at once, including YouTube, Twitch, Facebook, LinkedIn, and TikTok, without running separate broadcasts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Restream Studio$q$, $q$A browser-based, no-download production studio for switching scenes, adding branded overlays, and hosting multiple on-screen participants.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Guest and team collaboration$q$, $q$Invite remote guests onto a virtual set and, on higher tiers, give team members shared access to manage broadcasts together.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Restream Chat$q$, $q$Aggregates comments and reactions from every connected platform into one unified chat feed for hosts and moderators.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Cloud recording$q$, $q$Automatically records every broadcast to the cloud for later download, review, or repurposing into other content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Analytics dashboard$q$, $q$Reports viewership and engagement metrics across all connected channels from a single view.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Custom branded layouts$q$, $q$Apply custom overlays, logos, and scene layouts to broadcasts so streams match a creator's or brand's visual identity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$AI-assisted clip generation$q$, $q$An add-on that automatically extracts short highlight clips from recorded broadcasts for repurposing on social platforms.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$RTMP and SRT ingest$q$, $q$Accepts an incoming stream from external encoders like OBS or vMix and fans it out to multiple destinations.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Public API$q$, $q$Lets developers and larger organizations automate stream setup and channel configuration programmatically.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Free plan lets creators try multistreaming before paying for anything$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Broad platform coverage, reaching dozens of destinations from one broadcast$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Browser-based Studio requires no software installation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Restream Chat unifies audience interaction across every connected platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Scales from solo creators on the free tier up to teams on Business or Enterprise plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Free plan is limited to two channels and includes Restream branding$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Higher resolution, longer recording retention, and guest features require paid tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$AI clip generation is a separate paid add-on rather than included by default$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Broadcast quality depends on a stable connection to Restream's servers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Enterprise-level features require contacting sales instead of transparent published pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$What is Restream used for?$q$, $q$Restream is used to broadcast one live video feed to multiple platforms at the same time, such as YouTube, Twitch, Facebook, and LinkedIn, instead of streaming to each platform separately.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Does Restream have a free plan?$q$, $q$Yes, Restream offers a free plan that supports multistreaming to two channels at once, though it includes Restream branding and fewer features than the paid tiers.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Can I use Restream with OBS or vMix?$q$, $q$Yes, Restream accepts an incoming RTMP or SRT stream from external encoders like OBS or vMix and distributes it to the connected destination platforms.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Does Restream require any software to be installed?$q$, $q$No installation is required to use Restream Studio, since it runs directly in a web browser; using an external encoder like OBS is optional rather than required.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$How much do Restream's paid plans cost?$q$, $q$Paid plans start with the Standard tier at $16 per month when billed annually, moving up through Professional and Business tiers, with Enterprise pricing available by contacting sales.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Solo streaming and gaming$q$, $q$A streamer broadcasts gameplay or a talk show once and appears live on Twitch, YouTube, and Facebook simultaneously.$q$, $q$Individual streamers and gamers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Podcast and interview distribution$q$, $q$A host records a video conversation once and distributes it to multiple platforms, then clips highlights for social media.$q$, $q$Podcasters and interview-format creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Company webinars and product launches$q$, $q$A marketing team streams a webinar or launch event to LinkedIn, YouTube, and a company website at the same time.$q$, $q$Marketing teams and small businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Community and organizational broadcasts$q$, $q$A church, nonprofit, or community group streams services or events to Facebook and YouTube together to reach members wherever they watch.$q$, $q$Community organizations and nonprofits$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, $q$["2 simultaneous channels","Multistreaming at no cost","Restream branding included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Standard$q$, $q$$16/month billed annually ($19/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["3 simultaneous channels","No Restream branding","Guest channels","720p HD quality","15 days of cloud recording storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Professional$q$, $q$$39/month billed annually ($49/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["5 simultaneous channels","1080p Full HD streaming","Up to 10 on-screen participants","30 days of cloud recording storage","Custom layouts"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Business$q$, $q$$199/month billed annually ($239/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["8 simultaneous channels","Website player for large concurrent audiences","2 included team seats","Co-producer mode","Dedicated infrastructure"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Restream began life as a simple relay service that took one live video feed and pushed it out to several destinations at once, and it has grown into a broader live-production platform while keeping that original idea at its core. Founded in 2014, the company lets streamers, podcasters, and businesses go live once and appear simultaneously on YouTube, Twitch, Facebook, LinkedIn, X, TikTok, and dozens of other destinations, without running separate encoders or duplicate broadcasts for each platform. The product is built around eliminating the technical overhead of reaching an audience that is spread across many different apps and websites.$q$, $q$At the center of the platform is Restream Studio, a browser-based production tool that requires no software installation. Inside Studio, a host can invite guests onto a virtual set, switch between scenes, add branded overlays and lower thirds, and share their screen, all while the platform simultaneously encodes and distributes the resulting feed to every connected channel. For creators who already produce with OBS, vMix, or a hardware encoder, Restream also accepts a single incoming RTMP or SRT feed and fans it out to multiple platforms, so existing production workflows do not need to change.$q$, $q$Restream was founded in Vinnytsia, Ukraine, and has since grown into a distributed company with offices in Austin, Tallinn, Kyiv, and Cascais. As the team expanded, the product expanded with it: what started as a restreaming relay now also includes a cross-platform chat aggregator, cloud recording, viewer analytics, and short-form clip generation, positioning Restream as a fuller live-streaming toolkit rather than a single-purpose utility.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$who-restream-is-for$q$, $q$Who Restream Is For$q$, 2, ARRAY[$q$Restream is a strong fit for individual streamers and gamers who want to grow their audience across several platforms without doubling their production effort, since a single broadcast can appear on Twitch and YouTube and Facebook at the same time. It also suits podcasters and interview-style creators who want to record a conversation once and distribute it everywhere their listeners already are, including as short clips for social discovery.$q$, $q$Small teams, marketing departments, and community organizations that run webinars, product launches, or town halls also fit well, particularly once they need guest collaboration, custom branded layouts, or a workspace that several team members can access together. For these groups, the paid tiers add the polish and reach that a single-platform livestream cannot offer on its own.$q$, $q$Organizations that already have an established production pipeline built around OBS, vMix, or a hardware switcher can use Restream purely as a distribution layer, feeding it one RTMP or SRT stream and letting it handle the multiplatform delivery. This lets an existing production team add reach without changing the tools they already know.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Restream is less useful for anyone who only ever streams to a single platform and has no plans to expand, since the extra cost and setup of a multistreaming layer add complexity without a corresponding benefit over streaming natively. In that case, a platform's own built-in streaming tools are simpler and free.$q$, $q$Teams that need heavy customization, very large participant counts, or guaranteed enterprise-grade infrastructure may find the self-serve Standard and Professional plans limiting and will need to move to Business or negotiate an Enterprise agreement, which comes without published pricing and requires a sales conversation.$q$, $q$Creators with unreliable or limited upload bandwidth should also be cautious, because simulcasting several high-quality streams from a browser depends on a stable connection to Restream's servers; a weak connection can lead to dropped frames or reduced quality across every destination at once rather than just one.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Restream's feature set centers on simultaneous multiplatform broadcasting, letting one live source reach dozens of destinations including YouTube, Twitch, Facebook, LinkedIn, and TikTok from a single dashboard, with per-channel titles, thumbnails, and descriptions configurable before going live. Restream Studio adds a no-download production layer with scene switching, custom branded overlays, and support for multiple on-screen participants and remote guests.$q$, $q$Restream Chat consolidates viewer comments and reactions from every connected platform into a single feed, so a host or moderator can respond to the whole audience without switching between separate platform windows. Cloud recording automatically captures each broadcast for later download or repurposing, while a built-in analytics dashboard reports viewership and engagement across the connected channels in one place.$q$, $q$For creators who want to turn long broadcasts into short-form social content, Restream offers an AI-assisted clipping add-on that extracts highlight moments from recorded streams. Developers and larger organizations can also work against Restream's public API to automate stream configuration, and the platform supports RTMP and SRT ingest for teams that prefer to produce in external software before Restream handles distribution.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$the-restream-experience$q$, $q$The Restream Experience$q$, 2, ARRAY[$q$Using Restream generally starts with connecting the destination accounts a creator wants to broadcast to, a process handled through OAuth-style logins for each platform rather than manual key entry. From there, a broadcast can be launched either straight from Restream Studio in the browser or by pointing an external encoder at Restream's ingest server, and both paths lead to the same multi-destination output.$q$, $q$The dashboard is organized around the live broadcast view, with channel status, chat, and layout controls visible at once, which keeps the learning curve relatively shallow for anyone who has used a single streaming platform before. Setting up branded overlays and custom layouts takes more deliberate configuration, but the free plan gives new users enough room to test the core multistreaming concept before committing to a paid tier.$q$, $q$Overall, the day-to-day experience favors creators who want to manage one broadcast rather than several separate ones, trading a bit of setup complexity up front for less duplicated effort every time they go live. Paid tiers layer on higher resolution, longer recording retention, and team features as a broadcaster's needs grow.$q$]::text[], 4);
