INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
